import {useState, useRef} from "react";
import {Link, useLocation} from "react-router-dom";
import { FiMenu } from "react-icons/fi";
import Logo from "../../elements/logo/Logo";
import Nav from './Nav';
// import MobileMenu from './MobileMenu';
// import Darkmode from "./Darkmode";
import useStickyHeader from "./useStickyHeader";
import useLangPath from "../../hooks/useLangPath";
import { useLang } from "../../context/LangContext";


const LANGS = ['en', 'tr'];

const HeaderOne = ({btnStyle, HeaderSTyle}) => {
    const langPath = useLangPath();
    const lang = useLang();
    const location = useLocation();
    // const [ofcanvasShow, setOffcanvasShow] = useState(false);
    // const onCanvasHandler = () => {
    //     setOffcanvasShow(prev => !prev);
    // }
    const ref = useRef();
    let [check, setCheck] = useState(true);
    const sticky = useStickyHeader( 50 );
    const headerClasses = `header-default ${(sticky && check) ? 'sticky' : ''}`
    // const { clientHeight } = ref;
    
    const checkChange = (value) => {
      setCheck(value);
    };
    return (
        <>
            <header ref={ref} className={`rn-header header-default ${HeaderSTyle} ${headerClasses}`}>
                <div className="container position-relative">
                    <div className="row align-items-center justify-content-center row--0">
                        <div className="col-lg-3 col-md-6 col-4 justify-content-center overflow-hidden">
                            <Link to={langPath("/labs")}>
                                <Logo
                                    image={`${process.env.PUBLIC_URL}/images/logo/axvelo_logo.png`}
                                    image2={`${process.env.PUBLIC_URL}/images/logo/axvelo_logo.png`}
                                />
                            </Link>
                        </div>
                        <div className="col-lg-9 col-md-6 col-8 d-flex justify-content-end align-items-center">
                            <div className="d-flex" style={{ gap: '4px' }}>
                                {LANGS.map(l => {
                                    const params = new URLSearchParams(location.search);
                                    params.set('lang', l);
                                    return (
                                    <Link
                                        key={l}
                                        to={{ pathname: location.pathname, search: params.toString() }}
                                        style={{
                                            padding: '4px 10px',
                                            fontWeight: l === lang ? '700' : '400',
                                            opacity: l === lang ? 1 : 0.5,
                                            fontSize: '13px',
                                            letterSpacing: '0.5px',
                                            textTransform: 'uppercase',
                                            color: 'var(--color-primary)',
                                            textDecoration: 'none',
                                        }}
                                    >
                                        {l}
                                    </Link>
                                    );
                                })}
                            </div>
                        </div>
                        {/* <div className="col-lg-3 col-md-6 col-4">
                            <Logo 
                                image={`${process.env.PUBLIC_URL}/images/logo/logo.png`}
                                image2={`${process.env.PUBLIC_URL}/images/logo/logo-dark.png`}
                            />
                        </div> */}
                        {/* <div className="col-lg-9 col-md-6 col-8 position-static">
                            <div className="header-right">
                                <nav className="mainmenu-nav d-none d-lg-block">
                                    <Nav />
                                </nav>
                                <div className="header-btn">
                                    <a className={`btn-default ${btnStyle}`} target="_blank" href="https://themeforest.net/checkout/from_item/33571911?license=regular">BUY NOW</a>
                                </div>
                                <div className="mobile-menu-bar ml--5 d-block d-lg-none">
                                    <div className="hamberger">
                                        <span className="hamberger-button" onClick={onCanvasHandler}><FiMenu /></span>
                                    </div>
                                </div>
                                <Darkmode />
                            </div>  
                        </div> */}
                    </div>
                </div>
            </header>
            {/* <MobileMenu show={ofcanvasShow} onClose={onCanvasHandler}  /> */}
        </>
    )
}
export default HeaderOne;