import PropTypes from "prop-types";
import React, { useState } from 'react';
import Slider from "react-slick";
import FsLightbox from "fslightbox-react";

const PrevArrow = ({ onClick }) => (
    <button 
        className="slick-arrow slick-prev image-slider-arrow image-slider-prev" 
        onClick={onClick} aria-label="Previous"
        style={{
            width:'35px',
            height:'35px'
        }}
    >
    </button>
);

const NextArrow = ({ onClick }) => (
    <button 
        className="slick-arrow slick-next image-slider-arrow image-slider-next" 
        onClick={onClick} aria-label="Next"
        style={{
            width:'35px',
            height:'35px'
        }}
    >
    </button>
);

const ImageSlider = ({ images, interval = 30000, showDots = true }) => {
    const [lightboxOpen, setLightboxOpen] = useState(false);
    const [lightboxIndex, setLightboxIndex] = useState(1);

    const openLightbox = (index) => {
        setLightboxIndex(index + 1);
        setLightboxOpen((prev) => !prev);
    };

    const settings = {
        infinite: true,
        slidesToShow: 3,
        slidesToScroll: 3,
        autoplay: true,
        autoplaySpeed: interval,
        dots: showDots,
        arrows: true,
        prevArrow: <PrevArrow />,
        nextArrow: <NextArrow />,
        pauseOnHover: true,
        responsive: [
          {
            breakpoint: 768,
            settings: {
              slidesToShow: 2,
              slidesToScroll: 2
            }
          },
          {
            breakpoint: 480,
            settings: {
              slidesToShow: 1,
              slidesToScroll: 1
            }
          }
        ]
    };

    return (
        <div
            className="image-slider-wrapper rn-slick-dot rn-slick-arrow slider-container"
            style={{ 
                paddingBottom: '40px'
            }}
        >
            <Slider {...settings}>
                {images.map((image, index) => (
                    <div className="image-slider-item" key={index}>
                        <img
                            onClick={() => openLightbox(index)}
                            src={image}
                            alt={`slide-${index + 1}`}
                            style={{ cursor: 'pointer' }}
                        />
                    </div>
                ))}
            </Slider>
            <FsLightbox
                toggler={lightboxOpen}
                sources={images}
                sourceIndex={lightboxIndex - 1}
            />
        </div>
    );
};

ImageSlider.propTypes = {
    images: PropTypes.arrayOf(PropTypes.string).isRequired,
    interval: PropTypes.number,
    showDots: PropTypes.bool,
};

export default ImageSlider;