import React, { useState, useEffect } from "react";
import BlogClassicData from '../../../data/blog/BlogList';
import BlogListTwo from './BlogListTwo';
import { FaSpinner } from "react-icons/fa";
import filters from "./Filters";
import { useT, useLang } from "../../../context/LangContext";


const BlogPropTwo = ({ column, StyleVarProp }) => {
    const t = useT();
    const lang = useLang();
    const allItems = BlogClassicData.map(post => ({
        id: post.id,
        categories: post.categories ?? [],
        tags: post.tags ?? [],
        ...(post[lang] ?? post.en),
    }));

    const [dataVisibleCount, setDataVisibleCount] = useState(6);
    const [dataIncrement] = useState(3);
    const [noMorePost, setNoMorePost] = useState(false);
    const [activeFilter, setActiveFilter] = useState("");
    const [visibleItems, setVisibleItems] = useState([]);

    useEffect(() => {
        setActiveFilter(filters[0].text.toLowerCase());
        setVisibleItems(allItems.filter((item) => item.id <= dataVisibleCount));
    }, [lang]);

    const handleLoadmorebl = (e) => {
        e.preventDefault();
        let tempCount = dataVisibleCount + dataIncrement;
        if (dataVisibleCount >= allItems.length) {
            setNoMorePost(true);
        } else {
            setDataVisibleCount(tempCount);
            if (activeFilter === filters[0].text.toLowerCase()) {
                setVisibleItems(allItems.filter((data) => data.id <= tempCount));
            } else {
                setVisibleItems(
                    allItems.filter(
                        (data) => data.text === activeFilter && data.id <= tempCount
                    )
                );
            }
        }
    }

    return (
        <>
            <div className="col-lg-12">
                <div className="row row--15">
                    {visibleItems.map((item) => (
                        <div key={item.id} className={column}>
                            <BlogListTwo StyleVar={StyleVarProp} data={item} />
                        </div>
                    ))}
                </div>
            </div>
            <div className="col-lg-12">
                <div className="rwt-load-more text-center mt--60">
                    <button
                        className="btn btn-default btn-icon"
                        onClick={handleLoadmorebl}
                        disabled={noMorePost ? "disabled" : null}
                    >
                        {noMorePost ? (
                            t.blog.noMorePost
                        ) : (
                            <span>
                                {t.blog.loadMore}
                                <span className="icon">
                                    <FaSpinner />
                                </span>
                            </span>
                        )}
                    </button>
                </div>
            </div>
        </>
    )
}
export default BlogPropTwo;
