import React from 'react';
import { Redirect } from 'react-router-dom';
import BlogClassicData from '../data/blog/BlogList';
import BlogDetailsContent from '../components/blog/BlogDetailsContent';
import SEO from "../common/SEO";
import Layout from "../common/Layout";
import { useLang } from '../context/LangContext';
import useLangPath from '../hooks/useLangPath';

const BlogDetails = ({ id }) => {
    const lang = useLang();
    const langPath = useLangPath();
    const blogId = parseInt(id, 10);
    const raw = BlogClassicData.find(post => post.id === blogId);
    const post = raw ? { id: raw.id, ...(raw[lang] ?? raw.en) } : null;

    if (!post) return <Redirect to={langPath('/error')} />;

    return (
        <>
            <SEO title={`Axvelo Labs Blog || ${post.title}`} />
            <Layout>
                <div className="rn-blog-details-area">
                    <BlogDetailsContent data={post} />
                </div>
            </Layout>
        </>
    )
}
export default BlogDetails;
